const express = require('express');
const MongoClient = require('mongodb').MongoClient;


// const app = express();
var url=process.env.MONGODB_URL || "mongodb://192.168.37.40:5000";  //for AWS instance
MongoClient.connect(url,{useUnifiedTopology:true},function (err,client){
    if (!err) {
        var db = client.db("task-manager");
        
        const app=express();

        app.post("/find", function (req, res) 
        {
            const body = req.body;

            //find method in mongo db, filter json object from front end request, 
            //which we will call from postman 
            db.collection('task').findOne(req.body,(err,doc)=>{
                if(!err){
                    console.log(JSON.stringify(doc));
                    res.send({
                        error:false, 
                        result:doc
                    })  
                }
            });

            
        })
        app.listen(3000);
    }
    
        
})